"use client"
import React from 'react'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import {
    Users, Clock, Bookmark, Flag, ChevronDown,
    Store, Tv, Gamepad2, CalendarDays
} from 'lucide-react'
import { useAuth } from '@/context/AuthContext'

const getInitials = (name: string) =>
    name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || 'U'

const shortcuts = [
    { icon: Users,       label: 'Friends',     color: '#1877f2', bg: '#e7f3ff' },
    { icon: Clock,       label: 'Memories',    color: '#e15241', bg: '#fce8e6' },
    { icon: Bookmark,    label: 'Saved',       color: '#7c3aed', bg: '#ede9fe' },
    { icon: Flag,        label: 'Pages',       color: '#f59e0b', bg: '#fef3c7' },
    { icon: Store,       label: 'Marketplace', color: '#059669', bg: '#d1fae5' },
    { icon: Tv,          label: 'Watch',       color: '#0ea5e9', bg: '#e0f2fe' },
    { icon: Gamepad2,    label: 'Gaming',      color: '#6366f1', bg: '#e0e7ff' },
    { icon: CalendarDays,label: 'Events',      color: '#e15241', bg: '#fce8e6' },
]

const LeftSidebar = () => {
    const { user } = useAuth()
    const initials = getInitials(user?.name || '')

    return (
        <aside className="hidden lg:flex flex-col w-70 shrink-0 h-[calc(100vh-56px)] sticky top-14 overflow-y-auto py-3 px-2 scrollbar-hide">

            {/* Profile link */}
            <button className="flex items-center gap-3 px-2 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors w-full text-left group">
                <Avatar className="w-9 h-9 ring-2 ring-[#1877f2]/20">
                    <AvatarImage />
                    <AvatarFallback className="bg-[#1877f2] text-white font-bold text-sm">{initials}</AvatarFallback>
                </Avatar>
                <span className="font-semibold text-[15px] text-[#050505] dark:text-[#e4e6eb] group-hover:text-[#1877f2] transition-colors">
                    {user?.name || 'Your Name'}
                </span>
            </button>

            {/* Nav items */}
            <div className="mt-1 space-y-0.5">
                {shortcuts.map(({ icon: Icon, label, color, bg }) => (
                    <button
                        key={label}
                        className="flex items-center gap-3 px-2 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors w-full text-left group"
                    >
                        <div
                            className="w-9 h-9 rounded-full flex items-center justify-center shrink-0"
                            style={{ backgroundColor: bg }}
                        >
                            <Icon className="w-4.5 h-4.5" style={{ color }} />
                        </div>
                        <span className="text-[15px] font-medium text-[#050505] dark:text-[#e4e6eb]">{label}</span>
                    </button>
                ))}
            </div>

            {/* See more */}
            <button className="flex items-center gap-3 px-2 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors w-full text-left mt-0.5">
                <div className="w-9 h-9 rounded-full bg-[#e4e6eb] dark:bg-[#3a3b3c] flex items-center justify-center shrink-0">
                    <ChevronDown className="w-4.5 h-4.5 text-[#050505] dark:text-[#e4e6eb]" />
                </div>
                <span className="text-[15px] font-medium text-[#050505] dark:text-[#e4e6eb]">See more</span>
            </button>

            <div className="h-px bg-[#dddfe2] dark:bg-[#3e4042] my-3 mx-2" />

            {/* Shortcuts section */}
            <div className="px-2">
                <div className="flex items-center justify-between mb-2">
                    <h3 className="text-[17px] font-semibold text-[#050505] dark:text-[#e4e6eb]">Your shortcuts</h3>
                    <button className="text-[14px] text-[#1877f2] font-medium hover:bg-[#e7f3ff] dark:hover:bg-[#263951] px-2 py-1 rounded-lg transition-colors">
                        Edit
                    </button>
                </div>
                <p className="text-[13px] text-[#65676b] dark:text-[#b0b3b8]">
                    Shortcuts you add will appear here.
                </p>
            </div>

            {/* Footer */}
            <div className="mt-auto pt-4 px-2">
                <p className="text-[12px] text-[#65676b] dark:text-[#b0b3b8] leading-relaxed">
                    Privacy · Terms · Advertising · Ad Choices · Cookies · More · Meta © {new Date().getFullYear()}
                </p>
            </div>
        </aside>
    )
}

export default LeftSidebar
