"use client"
import React, { useCallback, useEffect, useRef, useState } from 'react'
import Image from 'next/image'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import {
    ImageIcon, Video, Smile, ThumbsUp, MessageCircle,
    Share2, MoreHorizontal, Plus, X, Loader2, Send,
} from 'lucide-react'
import { postsApi } from '@/lib/api'
import { useAuth } from '@/context/AuthContext'

// ─── Types ────────────────────────────────────────────────────────────────────

interface Author {
    id: string
    firstName: string
    lastName: string
    avatar: string | null
}

interface PostRecord {
    id: string
    content: string | null
    image: string | null
    authorId: string
    createdAt: string
    updatedAt: string
    author: Author
    _count?: { likes: number; comments: number }
}

interface Comment {
    id: string
    content: string
    createdAt: string
    author: Author
    replies?: Comment[]
}

// ─── Stories data ─────────────────────────────────────────────────────────────

const stories = [
    { name: 'Your Story', fallback: 'Y', color: 'from-blue-500 to-blue-600', isCreate: true },
    { name: 'Alice J.',   fallback: 'AJ', color: 'from-pink-500 to-rose-500' },
    { name: 'Bob S.',     fallback: 'BS', color: 'from-emerald-500 to-green-600' },
    { name: 'Carol W.',   fallback: 'CW', color: 'from-violet-500 to-purple-600' },
    { name: 'David L.',   fallback: 'DL', color: 'from-orange-400 to-amber-500' },
]

// ─── Helpers ──────────────────────────────────────────────────────────────────

const timeAgo = (iso: string) => {
    const diff = Date.now() - new Date(iso).getTime()
    const mins = Math.floor(diff / 60000)
    if (mins < 1)  return 'Just now'
    if (mins < 60) return `${mins}m`
    const hrs = Math.floor(mins / 60)
    if (hrs < 24)  return `${hrs}h`
    return `${Math.floor(hrs / 24)}d`
}

const initials = (first: string, last: string) =>
    `${first[0] ?? ''}${last[0] ?? ''}`.toUpperCase()

const API_BASE = process.env.NEXT_PUBLIC_API_URL?.replace('/api', '') ?? 'http://localhost:5001'

// ─── Stories Row ─────────────────────────────────────────────────────────────

const StoriesRow = () => (
    <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
        {stories.map((story) => (
            <div
                key={story.name}
                className="relative shrink-0 w-[112px] h-[196px] rounded-2xl overflow-hidden cursor-pointer group shadow-sm hover:shadow-md transition-shadow"
            >
                <div className={`absolute inset-0 bg-gradient-to-b ${story.color}`} />
                <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-black/60" />

                {/* Avatar ring */}
                <div className="absolute top-3 left-3">
                    {story.isCreate ? (
                        <div className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-sm border-2 border-white/40 flex items-center justify-center shadow-lg">
                            <Plus className="w-5 h-5 text-white" strokeWidth={2.5} />
                        </div>
                    ) : (
                        <div className="w-10 h-10 rounded-full bg-white/20 backdrop-blur-sm border-[3px] border-[#1877f2] flex items-center justify-center text-white text-xs font-bold shadow-lg">
                            {story.fallback}
                        </div>
                    )}
                </div>

                <p className="absolute bottom-3 left-0 right-0 text-center text-white text-[11px] font-semibold px-2 leading-tight drop-shadow">
                    {story.name}
                </p>
            </div>
        ))}
    </div>
)

// ─── Create Post ──────────────────────────────────────────────────────────────

interface CreatePostProps {
    onPostCreated: (post: PostRecord) => void
}

const CreatePost = ({ onPostCreated }: CreatePostProps) => {
    const { user } = useAuth()
    const [expanded, setExpanded]   = useState(false)
    const [content, setContent]     = useState('')
    const [image, setImage]         = useState<File | null>(null)
    const [preview, setPreview]     = useState<string | null>(null)
    const [loading, setLoading]     = useState(false)
    const [error, setError]         = useState<string | null>(null)
    const fileRef = useRef<HTMLInputElement>(null)

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0] ?? null
        if (!file) return
        const allowed = ['image/jpeg', 'image/png', 'image/gif', 'image/webp']
        if (!allowed.includes(file.type)) { setError('Only JPEG, PNG, GIF, or WebP images are allowed.'); return }
        setImage(file)
        setPreview(URL.createObjectURL(file))
        setError(null)
    }

    const removeImage = () => {
        setImage(null)
        if (preview) URL.revokeObjectURL(preview)
        setPreview(null)
        if (fileRef.current) fileRef.current.value = ''
    }

    const handleSubmit = async () => {
        const trimmed = content.trim()
        if (!trimmed && !image) { setError('Add some text or a photo before posting.'); return }
        setLoading(true); setError(null)
        try {
            const data = await postsApi.create({ content: trimmed, image })
            setContent(''); removeImage(); setExpanded(false)
            if (data?.post) onPostCreated(data.post)
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : 'Failed to create post.')
        } finally {
            setLoading(false)
        }
    }

    const userInitials = user ? initials(user.firstName, user.lastName) : 'U'

    return (
        <div className="bg-white dark:bg-[#242526] rounded-2xl shadow-sm border border-[#ced0d4] dark:border-[#3e4042] p-3">
            <div className="flex items-center gap-2 mb-3">
                <Avatar className="w-10 h-10 shrink-0">
                    <AvatarImage src={user?.avatar ?? undefined} />
                    <AvatarFallback className="bg-[#1877f2] text-white font-semibold text-sm">{userInitials}</AvatarFallback>
                </Avatar>
                {!expanded ? (
                    <button
                        onClick={() => setExpanded(true)}
                        className="flex-1 bg-[#f0f2f5] dark:bg-[#3a3b3c] hover:bg-[#e4e6eb] dark:hover:bg-[#4e4f50] rounded-full px-4 py-2.5 text-left text-sm text-[#65676b] dark:text-[#b0b3b8] transition-colors font-normal"
                    >
                        What&apos;s on your mind, {user?.firstName ?? 'you'}?
                    </button>
                ) : (
                    <textarea
                        autoFocus
                        value={content}
                        onChange={(e) => { setContent(e.target.value); setError(null) }}
                        placeholder={`What's on your mind, ${user?.firstName ?? 'you'}?`}
                        rows={3}
                        className="flex-1 bg-transparent resize-none outline-none text-[15px] dark:text-[#e4e6eb] placeholder-[#65676b] dark:placeholder-[#b0b3b8] leading-relaxed"
                    />
                )}
            </div>

            {preview && (
                <div className="relative mb-3 rounded-xl overflow-hidden bg-[#f0f2f5] dark:bg-[#3a3b3c]">
                    <Image src={preview} alt="Preview" width={600} height={400} className="w-full object-cover max-h-72" unoptimized />
                    <button onClick={removeImage} className="absolute top-2 right-2 bg-white/90 dark:bg-[#3a3b3c]/90 hover:bg-white dark:hover:bg-[#4e4f50] text-[#050505] dark:text-[#e4e6eb] rounded-full p-1.5 shadow transition-colors" aria-label="Remove image">
                        <X className="w-4 h-4" />
                    </button>
                </div>
            )}

            {error && <p className="text-xs text-red-500 mb-2 px-1">{error}</p>}

            <div className="border-t border-[#ced0d4] dark:border-[#3e4042] pt-2 mt-1">
                <div className="flex items-center justify-between">
                    <div className="flex items-center">
                        <input ref={fileRef} type="file" accept="image/jpeg,image/png,image/gif,image/webp" className="hidden" onChange={handleFileChange} />
                        <button onClick={() => { setExpanded(true); fileRef.current?.click() }} className="flex items-center gap-2 px-3 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors">
                            <ImageIcon className="w-5 h-5 text-[#45bd62]" />
                            <span className="text-sm font-medium text-[#65676b] dark:text-[#b0b3b8] hidden sm:inline">Photo/video</span>
                        </button>
                        <button className="flex items-center gap-2 px-3 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors">
                            <Video className="w-5 h-5 text-[#f3425f]" />
                            <span className="text-sm font-medium text-[#65676b] dark:text-[#b0b3b8] hidden sm:inline">Live video</span>
                        </button>
                        <button className="flex items-center gap-2 px-3 py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors">
                            <Smile className="w-5 h-5 text-[#f7b928]" />
                            <span className="text-sm font-medium text-[#65676b] dark:text-[#b0b3b8] hidden sm:inline">Feeling</span>
                        </button>
                    </div>
                    {expanded && (
                        <button onClick={handleSubmit} disabled={loading} className="px-5 py-2 bg-[#1877f2] hover:bg-[#166fe5] disabled:opacity-50 disabled:cursor-not-allowed text-white text-sm font-semibold rounded-xl transition-colors flex items-center gap-2">
                            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                            Post
                        </button>
                    )}
                </div>
            </div>
        </div>
    )
}

// ─── Post Card ────────────────────────────────────────────────────────────────

const PostCard = ({ post: initialPost }: { post: PostRecord }) => {
    const { user } = useAuth()
    const [post, setPost]                   = useState(initialPost)
    const [liked, setLiked]                 = useState(false)
    const [showComments, setShowComments]   = useState(false)
    const [comments, setComments]           = useState<Comment[]>([])
    const [loadingComments, setLoadingComments] = useState(false)
    const [commentText, setCommentText]     = useState('')
    const [submitting, setSubmitting]       = useState(false)

    const name = `${post.author.firstName} ${post.author.lastName}`
    const fb   = initials(post.author.firstName, post.author.lastName)

    const handleLike = async () => {
        try {
            if (liked) {
                await postsApi.unlike(post.id)
                setLiked(false)
                setPost(p => ({ ...p, _count: { ...p._count, likes: Math.max(0, (p._count?.likes ?? 0) - 1) } }))
            } else {
                await postsApi.like(post.id)
                setLiked(true)
                setPost(p => ({ ...p, _count: { ...p._count, likes: (p._count?.likes ?? 0) + 1 } }))
            }
        } catch { /* silent */ }
    }

    const loadComments = async () => {
        if (comments.length > 0) return
        setLoadingComments(true)
        try {
            const data = await postsApi.getComments(post.id)
            setComments(data.comments ?? [])
        } catch { /* silent */ } finally { setLoadingComments(false) }
    }

    const handleCommentClick = () => {
        setShowComments(p => !p)
        if (!showComments) loadComments()
    }

    const handleSubmitComment = async () => {
        const trimmed = commentText.trim()
        if (!trimmed) return
        setSubmitting(true)
        try {
            const data = await postsApi.createComment(post.id, { content: trimmed })
            setComments(p => [...p, data.comment])
            setCommentText('')
            setPost(p => ({ ...p, _count: { ...p._count, comments: (p._count?.comments ?? 0) + 1 } }))
        } catch { /* silent */ } finally { setSubmitting(false) }
    }

    const likeCount    = post._count?.likes ?? 0
    const commentCount = post._count?.comments ?? 0

    return (
        <div className="bg-white dark:bg-[#242526] rounded-2xl shadow-sm border border-[#ced0d4] dark:border-[#3e4042] overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between px-4 pt-3 pb-2">
                <div className="flex items-center gap-3">
                    <Avatar className="w-10 h-10">
                        <AvatarImage src={post.author.avatar ? `${API_BASE}/${post.author.avatar}` : undefined} />
                        <AvatarFallback className="bg-[#1877f2] text-white font-semibold text-sm">{fb}</AvatarFallback>
                    </Avatar>
                    <div>
                        <p className="font-semibold text-[14px] text-[#050505] dark:text-[#e4e6eb] leading-tight">{name}</p>
                        <p className="text-[12px] text-[#65676b] dark:text-[#b0b3b8] flex items-center gap-1">
                            {timeAgo(post.createdAt)}
                            <span>·</span>
                            <svg className="w-3 h-3 fill-current" viewBox="0 0 16 16"><path d="M8 0a8 8 0 100 16A8 8 0 008 0zm0 14.5A6.5 6.5 0 118 1.5a6.5 6.5 0 010 13z"/><path d="M11.5 8H8V4.5a.5.5 0 00-1 0V8.5a.5.5 0 00.5.5h4a.5.5 0 000-1z" style={{display:'none'}}/></svg>
                            <span>Public</span>
                        </p>
                    </div>
                </div>
                <button className="p-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-full transition-colors">
                    <MoreHorizontal className="w-5 h-5 text-[#65676b] dark:text-[#b0b3b8]" />
                </button>
            </div>

            {/* Content */}
            {post.content && (
                <p className="px-4 pb-3 text-[15px] text-[#050505] dark:text-[#e4e6eb] leading-relaxed">{post.content}</p>
            )}

            {/* Image */}
            {post.image && (
                <div className="w-full bg-[#f0f2f5] dark:bg-[#3a3b3c]">
                    <Image src={`${API_BASE}/${post.image}`} alt="Post image" width={600} height={400} className="w-full object-cover max-h-[500px]" unoptimized />
                </div>
            )}

            {/* Counts row */}
            {(likeCount > 0 || commentCount > 0) && (
                <div className="flex items-center justify-between px-4 py-2">
                    {likeCount > 0 && (
                        <div className="flex items-center gap-1.5">
                            <div className="flex items-center justify-center w-[18px] h-[18px] rounded-full bg-[#1877f2]">
                                <ThumbsUp className="w-2.5 h-2.5 text-white fill-white" />
                            </div>
                            <span className="text-[13px] text-[#65676b] dark:text-[#b0b3b8]">{likeCount}</span>
                        </div>
                    )}
                    {commentCount > 0 && (
                        <button onClick={handleCommentClick} className="ml-auto text-[13px] text-[#65676b] dark:text-[#b0b3b8] hover:underline">
                            {commentCount} {commentCount === 1 ? 'comment' : 'comments'}
                        </button>
                    )}
                </div>
            )}

            {/* Divider */}
            <div className="mx-4 border-t border-[#ced0d4] dark:border-[#3e4042]" />

            {/* Action buttons */}
            <div className="flex items-center px-2 py-1">
                <button onClick={handleLike} className={`flex items-center gap-2 flex-1 justify-center py-2 rounded-xl transition-colors font-semibold text-[14px] ${liked ? 'text-[#1877f2]' : 'text-[#65676b] dark:text-[#b0b3b8] hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c]'}`}>
                    <ThumbsUp className={`w-[18px] h-[18px] ${liked ? 'fill-[#1877f2] text-[#1877f2]' : ''}`} strokeWidth={liked ? 0 : 2} />
                    Like
                </button>
                <button onClick={handleCommentClick} className="flex items-center gap-2 flex-1 justify-center py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors text-[#65676b] dark:text-[#b0b3b8] font-semibold text-[14px]">
                    <MessageCircle className="w-[18px] h-[18px]" />
                    Comment
                </button>
                <button className="flex items-center gap-2 flex-1 justify-center py-2 hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] rounded-xl transition-colors text-[#65676b] dark:text-[#b0b3b8] font-semibold text-[14px]">
                    <Share2 className="w-[18px] h-[18px]" />
                    Share
                </button>
            </div>

            {/* Comments section */}
            {showComments && (
                <div className="px-4 pb-3 border-t border-[#ced0d4] dark:border-[#3e4042] pt-3 space-y-3">
                    {/* Input */}
                    <div className="flex items-center gap-2">
                        <Avatar className="w-8 h-8 shrink-0">
                            <AvatarImage src={user?.avatar ?? undefined} />
                            <AvatarFallback className="bg-[#1877f2] text-white text-xs font-semibold">
                                {user ? initials(user.firstName, user.lastName) : 'U'}
                            </AvatarFallback>
                        </Avatar>
                        <div className="flex-1 flex items-center gap-2 bg-[#f0f2f5] dark:bg-[#3a3b3c] rounded-full px-4 py-2">
                            <input
                                type="text"
                                value={commentText}
                                onChange={e => setCommentText(e.target.value)}
                                onKeyDown={e => e.key === 'Enter' && handleSubmitComment()}
                                placeholder="Write a comment…"
                                className="flex-1 bg-transparent outline-none text-[13px] text-[#050505] dark:text-[#e4e6eb] placeholder-[#65676b] dark:placeholder-[#b0b3b8]"
                            />
                            {commentText.trim() && (
                                <button onClick={handleSubmitComment} disabled={submitting} className="text-[#1877f2] disabled:opacity-50">
                                    {submitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
                                </button>
                            )}
                        </div>
                    </div>

                    {loadingComments && <div className="flex justify-center py-2"><Loader2 className="w-5 h-5 animate-spin text-[#65676b]" /></div>}

                    {!loadingComments && comments.length === 0 && (
                        <p className="text-[13px] text-[#65676b] dark:text-[#b0b3b8] text-center py-1">No comments yet. Be the first!</p>
                    )}

                    {!loadingComments && comments.map(comment => (
                        <div key={comment.id} className="flex items-start gap-2">
                            <Avatar className="w-8 h-8 shrink-0">
                                <AvatarImage src={comment.author.avatar ? `${API_BASE}/${comment.author.avatar}` : undefined} />
                                <AvatarFallback className="bg-[#65676b] text-white text-xs font-semibold">
                                    {initials(comment.author.firstName, comment.author.lastName)}
                                </AvatarFallback>
                            </Avatar>
                            <div>
                                <div className="bg-[#f0f2f5] dark:bg-[#3a3b3c] rounded-2xl px-3 py-2 inline-block">
                                    <p className="text-[13px] font-semibold text-[#050505] dark:text-[#e4e6eb]">
                                        {comment.author.firstName} {comment.author.lastName}
                                    </p>
                                    <p className="text-[14px] text-[#050505] dark:text-[#e4e6eb]">{comment.content}</p>
                                </div>
                                <p className="text-[11px] text-[#65676b] dark:text-[#b0b3b8] mt-1 px-2">{timeAgo(comment.createdAt)}</p>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    )
}

// ─── Feed (main export) ───────────────────────────────────────────────────────

const Feed = () => {
    const [posts, setPosts]     = useState<PostRecord[]>([])
    const [page, setPage]       = useState(1)
    const [hasMore, setHasMore] = useState(true)
    const [loading, setLoading] = useState(false)
    const [error, setError]     = useState<string | null>(null)

    const fetchPosts = useCallback(async (pageNum: number) => {
        setLoading(true)
        setError(null)
        try {
            const data = await postsApi.getFeed({ page: pageNum, limit: 10 })
            const incoming: PostRecord[] = data.posts ?? []
            setPosts(prev => pageNum === 1 ? incoming : [...prev, ...incoming])
            setHasMore(incoming.length === 10)
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : 'Failed to load posts.')
        } finally {
            setLoading(false)
        }
    }, [])

    useEffect(() => { fetchPosts(1) }, [fetchPosts])

    const handlePostCreated = (post: PostRecord) => {
        setPosts(prev => [post, ...prev])
    }

    const loadMore = () => {
        const next = page + 1
        setPage(next)
        fetchPosts(next)
    }

    return (
        <div className="flex flex-col gap-3 max-w-[590px] mx-auto w-full">
            <StoriesRow />
            <CreatePost onPostCreated={handlePostCreated} />

            {error && (
                <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 text-sm px-4 py-3 rounded-2xl">
                    {error}
                </div>
            )}

            {loading && page === 1 && (
                <div className="flex justify-center py-8">
                    <Loader2 className="w-8 h-8 animate-spin text-[#1877f2]" />
                </div>
            )}

            {posts.map(post => (
                <PostCard key={post.id} post={post} />
            ))}

            {!loading && posts.length === 0 && !error && (
                <div className="bg-white dark:bg-[#242526] rounded-2xl shadow-sm border border-[#ced0d4] dark:border-[#3e4042] p-8 text-center">
                    <p className="text-[15px] text-[#65676b] dark:text-[#b0b3b8]">No posts yet. Be the first to share something!</p>
                </div>
            )}

            {hasMore && !loading && posts.length > 0 && (
                <button
                    onClick={loadMore}
                    className="w-full py-2.5 bg-white dark:bg-[#242526] border border-[#ced0d4] dark:border-[#3e4042] rounded-2xl text-[#1877f2] font-semibold text-sm hover:bg-[#f0f2f5] dark:hover:bg-[#3a3b3c] transition-colors shadow-sm"
                >
                    Load more
                </button>
            )}

            {loading && page > 1 && (
                <div className="flex justify-center py-4">
                    <Loader2 className="w-6 h-6 animate-spin text-[#1877f2]" />
                </div>
            )}
        </div>
    )
}

export default Feed
